# Test mixed-type arithmetic operations (int + float, int - float, etc.)

# Int + Float
result1: float = 5 + 2.5
print(result1)

# Int - Float
result2: float = 10 - 3.5
print(result2)

# Int * Float
result3: float = 4 * 2.5
print(result3)

# Int / Float (true division)
result4: float = 10 / 2.5
print(result4)

# Int // Float (floor division)
result5: float = 10 // 3.0
print(result5)

# Int % Float (modulo)
result6: float = 10 % 3.0
print(result6)

# Float + Int
result7: float = 2.5 + 5
print(result7)

# Float - Int
result8: float = 10.5 - 3
print(result8)

# Float * Int
result9: float = 2.5 * 4
print(result9)

# Float / Int
result10: float = 10.0 / 2
print(result10)
